use std::collections::HashMap;

fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let mut ans = Vec::new();
    for query in queries {
        let l = query[0] as usize;
        let r = query[1] as usize;
        let t = query[2] as i64;
        let mut freq = HashMap::new();
        for i in l..=r {
            let num = nums[i];
            *freq.entry(num).or_insert(0) += 1;
        }
        let mut max_freq = 0;
        let mut best_num = -1;
        for (&num, &count) in &freq {
            if count >= t {
                if count > max_freq || (count == max_freq && num < best_num) {
                    max_freq = count;
                    best_num = num;
                }
            }
        }
        ans.push(best_num);
    }
    ans
}
```

